`CollectStatusEvent` lets you centralise status logic in one place rather than scattering `self.unit.status = ...` calls across event handlers. Ops collects all statuses set during the event and picks the "worst" one automatically.

## How it works

1. Observe `collect_unit_status` (and/or `collect_app_status` for the leader).
2. In the handler, call `event.add_status(...)` — you can call it multiple times.
3. Ops picks the highest-priority status: `BlockedStatus` > `WaitingStatus` > `MaintenanceStatus` > `ActiveStatus`.

## Complete example

```python
"""Example charm using CollectStatusEvent."""

from __future__ import annotations

import dataclasses
import logging

import ops

logger = logging.getLogger(__name__)


@dataclasses.dataclass
class CharmConfig:
    port: int
    api_key: str

    @classmethod
    def from_charm(cls, charm: ops.CharmBase) -> CharmConfig:
        return cls(
            port=charm.config.get("port"),
            api_key=charm.config.get("api-key", ""),
        )


class MyCharm(ops.CharmBase):
    def __init__(self, framework: ops.Framework) -> None:
        super().__init__(framework)
        self._pebble_service_name = "myapp"

        framework.observe(self.on.myapp_pebble_ready, self._on_pebble_ready)
        framework.observe(self.on.config_changed, self._on_config_changed)
        framework.observe(self.on.collect_unit_status, self._on_collect_unit_status)

    def _on_pebble_ready(self, event: ops.PebbleReadyEvent) -> None:
        self._configure_workload(event.workload)

    def _on_config_changed(self, event: ops.ConfigChangedEvent) -> None:
        container = self.unit.get_container("myapp")
        if container.can_connect():
            self._configure_workload(container)

    def _configure_workload(self, container: ops.Container) -> None:
        config = CharmConfig.from_charm(self)
        layer = ops.pebble.Layer({
            "services": {
                self._pebble_service_name: {
                    "override": "replace",
                    "command": "/usr/bin/myapp",
                    "environment": {
                        "PORT": str(config.port),
                        "API_KEY": config.api_key,
                    },
                }
            }
        })
        container.add_layer(self._pebble_service_name, layer, combine=True)
        container.replan()

    # --- Status collection ---

    def _on_collect_unit_status(self, event: ops.CollectStatusEvent) -> None:
        # Check each concern independently and add a status for each.
        # Ops will surface the worst one.

        container = self.unit.get_container("myapp")
        if not container.can_connect():
            event.add_status(ops.WaitingStatus("waiting for Pebble"))
            return  # No point checking further if Pebble isn't ready

        config = CharmConfig.from_charm(self)
        if not config.api_key:
            event.add_status(ops.BlockedStatus("api-key config required"))

        try:
            service = container.get_service(self._pebble_service_name)
        except ops.ModelError:
            event.add_status(ops.WaitingStatus("service not yet started"))
            return

        if not service.is_running():
            event.add_status(ops.WaitingStatus("service not running"))
            return

        # Everything looks good
        event.add_status(ops.ActiveStatus())


if __name__ == "__main__":
    ops.main(MyCharm)
```

## Key points

- **No need to set status elsewhere** — remove `self.unit.status = ...` from event handlers; let `collect_unit_status` own all status decisions.
- **Early return is fine** — if a prerequisite fails (e.g. Pebble not ready), returning early avoids misleading statuses from later checks.
- **Multiple `add_status` calls** — useful when independent subsystems each have their own health check; Ops picks the worst automatically.
- **App status** — for the leader unit, also observe `collect_app_status` and call `event.add_status(...)` there to set `self.app.status`.
